                }`}
              >
                {tab.charAt(0).toUpperCase() + tab.slice(1)}
              </button>
            ))}
          </div>
        </div>

        {/* Tab Content */}
        <div className="mt-8 w-full max-w-4xl transition-opacity duration-300">
          {activeTab === 'register' && <RegisterTab />}
          {activeTab === 'recognition' && <RecognitionTab />}
          {activeTab === 'chat' && <ChatTab />}
        </div>
      </div>
    </div>
  );
};

export default App;

